import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import Breadcrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import EnterpriseBlockchainScreen from "@screens/Enterprise-blockchain";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const EnterpriseBlockchainPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Enterprise Blockchain Development Company", link: null },
  ];
  const { data } = props;
  const location = useLocation();

  const fileUrl =
    data?.enterpriseDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Enterprise blockchain development by Justtry Technologies helps businesses improve security, transparency, and efficiency with scalable solutions tailored for modern digital operations.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
          addressCountry: "IN",
        },
      },
      {
        "@type": "Product",
        name: validData?.title || "Blockchain Enterprise",
        description:
          "Enterprise-grade Web3 blockchain development services by a top Web3 development company. Secure, scalable, and custom blockchain solutions.",
        url: "https://justtrytech.com/enterprise-blockchain-development/",
        image:
          "https://justtrytech.com/static/c5fd68e28cbeeef3197f83638a06395f/414dd/enterprise-development.png",
        brand: {
          "@type": "Brand",
          name: "Justtry Technologies",
          logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        },
        review: {
          "@type": "Review",
          reviewRating: {
            "@type": "Rating",
            ratingValue: 4,
            bestRating: 5,
          },
          author: {
            "@type": "Person",
            name: "danieljt",
          },
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: 4.4,
          reviewCount: 1010,
        },
      },
      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "How to choose an enterprise blockchain solution provider?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Select an enterprise blockchain solution provider with proven expertise, strong security practices, scalable architecture, industry knowledge, and dependable support for long-term success.",
            },
          },
          {
            "@type": "Question",
            name: "What are the leading blockchain platforms for business applications?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Leading blockchain platforms for business applications include Ethereum, Hyperledger Fabric, Corda, and Polygon, offering security, scalability, smart contracts, and enterprise-grade performance.",
            },
          },
          {
            "@type": "Question",
            name: "What is enterprise blockchain development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Enterprise blockchain development is the process of building secure, scalable blockchain solutions that help businesses improve transparency, automate workflows, and enhance data integrity.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <EnterpriseBlockchainScreen db={db} />
    </Layout_v2>
  );
};

export default EnterpriseBlockchainPage;

export const queryData = graphql`
  query MyQuery {
    enterpriseDevImg: file(relativePath: { eq: "enterprise-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "enterprise-blockchain-development" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
